class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long len = 1;
        for (int op : operations) {
            if (op == 0) {
                len *= 2;
            } else {
                len = len * 2 - 1;
            }
        }
        long long index = k % len;
        long long i = 0;
        while (index > 0) {
            if (operations[i] == 0) {
                index /= 2;
            } else {
                index--;
                index /= 2;
            }
            i++;
        }
        return 'a' + i;
    }
};
```

